data class TrainingOption(
    val id: String,
    val title: String,
    val imageRes: Int
)

@Composable
fun TrainingScreen(
    onBack: () -> Unit,
    onSelect: (String) -> Unit,
    onOpenHome: () -> Unit = {},
    onOpenTraining: () -> Unit = {},
    onOpenChallenges: () -> Unit = {},
    onOpenProfile: () -> Unit = {}
) {
    val bg = Brush.verticalGradient(
        listOf(
            Color(0xFF1F3F73),
            Color(0xFF3A2F7A),
            Color(0xFF2A3344)
        )
    )

    val recent = listOf(
        TrainingOption("back", "Espalda", R.drawable.espalda),
        TrainingOption("fullbody", "Full Body", R.drawable.fullbody)
    )
    val beginners = listOf(
        TrainingOption("stretch", "Estiramientos", R.drawable.estiramientos),
        TrainingOption("push", "Empujes", R.drawable.pushup)
    )
    val muscle = listOf(
        TrainingOption("calves", "Gemelos", R.drawable.pierna),
        TrainingOption("arm", "Brazo", R.drawable.brazo)
    )

    Box(
        modifier = Modifier
            .fillMaxSize()
            .background(bg)
            .padding(start = 12.dp, end = 12.dp, bottom = 12.dp, top = 42.dp)
    ) {
        Surface(
            modifier = Modifier.fillMaxSize(),
            shape = RoundedCornerShape(34.dp),
            color = Color(0xFFD9D9D9),
            shadowElevation = 10.dp
        ) {
            Column(
                modifier = Modifier
                    .fillMaxSize()
                    .padding(top = 25.dp)
            ) {
                TrainingHeaderRow(onBack = onBack)

                Spacer(Modifier.height(14.dp))

                LazyColumn(
                    modifier = Modifier
                        .weight(1f)
                        .padding(horizontal = 14.dp),
                    verticalArrangement = Arrangement.spacedBy(16.dp),
                    contentPadding = PaddingValues(bottom = 12.dp)
                ) {
                    item {
                        TrainingSection(
                            title = "Recientes",
                            left = recent[0],
                            right = recent[1],
                            onSelect = onSelect
                        )
                    }
                    item {
                        TrainingSection(
                            title = "Para Principiantes",
                            left = beginners[0],
                            right = beginners[1],
                            onSelect = onSelect
                        )
                    }
                    item {
                        TrainingSection(
                            title = "Por Grupo Muscular",
                            left = muscle[0],
                            right = muscle[1],
                            onSelect = onSelect
                        )
                    }
                }

                BottomNavBar(
                    selectedItem = BottomNavItem.TRAINING,
                    onOpenHome = onOpenHome,
                    onOpenTraining = onOpenTraining,
                    onOpenChallenges = onOpenChallenges,
                    onOpenProfile = onOpenProfile
                )
            }
        }
    }
}

